import argparse
import json
import os
import numpy as np
from cogniplan_env import ExplorationEnv
import heapq
from collections import deque
import torch


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = tuple(np.round(n["coords"], 6))
        coord_to_idx[coord] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(tuple(np.round(nb, 6)))
            else:
                j = int(nb) if (0 <= int(nb) < N) else None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        j = coord_to_idx.get(tuple(np.round(nb, 6)))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class Explorer:
    def __init__(self):
        self.history = deque(maxlen=12)
        self.last_target = None
        self.step_count = 0

    def select_action(self, obs):
        robot_pos = np.array(obs["robot_pos"], dtype=np.float32)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)

        self.history.append(robot_pos.copy())
        self.step_count += 1
        steps_remaining = max(0, 128 - self.step_count)

        momentum_vec = None
        if len(self.history) >= 2:
            diff = self.history[-1] - self.history[-2]
            norm = np.linalg.norm(diff)
            if norm > 1e-3:
                momentum_vec = diff / norm

        best_score = -float('inf')
        best_j = None
        best_coord = None

        for j, n in enumerate(nodes):
            if j == r_idx:
                continue
            d = dist[j]
            if d == float('inf'):
                continue
            utility = float(n.get("utility", 0.0))
            if utility <= 0:
                continue

            visited = bool(n.get("visited", False))
            score = utility / (d + 3.6)
            if visited:
                score *= 0.05

            node_pos = np.array(n["coords"])
            for past_pos in self.history:
                if np.linalg.norm(node_pos - past_pos) < 7.2:
                    score *= 0.35
                    break

            if self.last_target is not None:
                if np.linalg.norm(node_pos - np.array(self.last_target)) < 0.6:
                    score *= 0.15

            if momentum_vec is not None:
                to_node = node_pos - robot_pos
                tn = np.linalg.norm(to_node)
                if tn > 0.1:
                    to_node = to_node / tn
                    cosine = float(np.dot(to_node, momentum_vec))
                    if cosine > 0:
                        score *= (1.0 + 0.12 * cosine)

            est_steps = d / 3.2
            if est_steps > steps_remaining:
                score = -1.0
            elif est_steps > steps_remaining * 0.65:
                score *= 0.4

            if score > best_score + 1e-9:
                best_score = score
                best_j = j
                best_coord = tuple(n["coords"])

        if best_j is None and frontiers:
            farr = np.array(frontiers)
            fdists = np.linalg.norm(farr - robot_pos, axis=1)
            nearest_f = farr[int(np.argmin(fdists))]
            best_val = float('inf')
            for j, n in enumerate(nodes):
                d = dist[j]
                if d == float('inf'):
                    continue
                nd = float(np.linalg.norm(np.array(n["coords"]) - nearest_f))
                val = nd + d * 0.5
                if val < best_val:
                    best_val = val
                    best_j = j
                    best_coord = tuple(n["coords"])

        if best_j is None:
            best_nb_score = -float('inf')
            best_nb = tuple(neighbors[0])
            for nb in neighbors:
                nb_pos = np.array(nb)
                s = 0.0
                for past_pos in self.history:
                    s += np.linalg.norm(nb_pos - past_pos)
                if s > best_nb_score:
                    best_nb_score = s
                    best_nb = tuple(nb)
            self.last_target = best_nb
            return best_nb

        cur = best_j
        for _ in range(len(nodes) + 5):
            if prev[cur] is None or prev[cur] == r_idx:
                break
            cur = prev[cur]

        if prev[cur] == r_idx:
            target_coord = tuple(nodes[cur]["coords"])
        else:
            target_coord = best_coord

        for nb in neighbors:
            if np.allclose(nb, target_coord, atol=1e-3):
                self.last_target = tuple(nb)
                return tuple(nb)

        closest = tuple(min(neighbors, key=lambda nb: np.linalg.norm(np.array(nb) - np.array(target_coord))))
        self.last_target = closest
        return closest


def run_episode(env, explorer):
    obs = env.reset()
    for step in range(128):
        target = explorer.select_action(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        _ = torch.load(ckpt_path, map_location="cpu")
    else:
        raise FileNotFoundError(f"Checkpoint not found: {ckpt_path}")

    eval_config_path = os.path.join(args.data_path, "eval_config.json")
    with open(eval_config_path, "r") as f:
        _ = json.load(f)

    maps_dir = os.path.join(args.data_path, "maps_eval")
    per_episode = []
    per_type = {}

    env_types = ["room", "tunnel", "outdoor"]
    for env_type in env_types:
        type_dir = os.path.join(maps_dir, env_type)
        if not os.path.isdir(type_dir):
            continue
        files = sorted([f for f in os.listdir(type_dir) if f.endswith(".png")])
        for fname in files:
            map_path = os.path.join(type_dir, fname)
            env = ExplorationEnv(map_path=map_path)
            explorer = Explorer()
            metrics = run_episode(env, explorer)
            success = 1 if metrics.get("success", False) else 0
            entry = {
                "map_path": f"{env_type}/{fname}",
                "env_type": env_type,
                "success": success,
                "travel_distance": float(metrics.get("travel_distance", 0.0)),
                "explored_rate": float(metrics.get("explored_rate", 0.0)),
            }
            per_episode.append(entry)

    total_episodes = len(per_episode)
    explored_rates = [e["explored_rate"] for e in per_episode]
    mean_explored_rate = float(np.mean(explored_rates)) if explored_rates else 0.0

    successes = [e for e in per_episode if e["success"] == 1]
    success_rate = len(successes) / total_episodes if total_episodes > 0 else 0.0
    travel_distances = [e["travel_distance"] for e in successes]
    mean_travel_distance = float(np.mean(travel_distances)) if travel_distances else 0.0

    for env_type in env_types:
        type_eps = [e for e in per_episode if e["env_type"] == env_type]
        if not type_eps:
            continue
        type_successes = [e for e in type_eps if e["success"] == 1]
        per_type[env_type] = {
            "explored_rate": float(np.mean([e["explored_rate"] for e in type_eps])),
            "travel_distance": float(np.mean([e["travel_distance"] for e in type_successes])) if type_successes else 0.0,
            "success_rate": len(type_successes) / len(type_eps),
        }

    result = {
        "explored_rate": mean_explored_rate,
        "travel_distance": mean_travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type,
        "total_episodes": total_episodes,
    }

    out_dir = os.path.dirname(args.output)
    if out_dir:
        os.makedirs(out_dir, exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(result, f, indent=2)


if __name__ == "__main__":
    main()
